 def rightSideView(self, root: Optional[TreeNode]) -> List[int]:
 if not root:
 return []

res = []
 cur = [root] # 当前深度的节点
 while cur:
 res.append(cur[-1].val)
 tmp = []
 for t in cur:
 if t.left:
 tmp.append(t.left) 
 if t.right:
 tmp.append(t.right) 
 cur = tmp
