 count_s[s[r]] += 1
 while count_s >= count_t:
 if r-l <= r_res-l_res:
 r_res, l_res = r, l
 count_s[s[l]] -= 1
 l += 1
 return '' if l_res == -1 else s[l_res: r_res+1]
